mapper.select:
SELECT id, owner_id, draft_id, note_id, storage_provider, bucket_name, object_key, public_url,
       file_name, media_type, content_type, size_bytes, etag, upload_status, sort_order,
       bound_at, created_at, updated_at
FROM `media_ref`
WHERE storage_provider = #{storageProvider}
  AND bucket_name = #{bucketName}
  AND object_key = #{objectKey}
